+function drawSoundIndicator(ctx: CanvasRenderingContext2D, x: number, y: number, type: string, frame: number) {
+  // Frame cycles 0..3
+  const size = 12;
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.lineWidth = 1.5;
+  ctx.strokeStyle = "orange";
+  ctx.fillStyle = "orange";
+
+  switch (type) {
+    case "forge":
+      // Orange impact lines radiating outward
+      ctx.strokeStyle = "orange";
+      ctx.lineWidth = 2;
+      ctx.beginPath();
+      const linesCount = 6;
+      for (let i = 0; i < linesCount; i++) {
+        const angle = (Math.PI * 2 / linesCount) * i + (frame * 0.5);
+        const length = 6 + frame * 2;
+        const startX = Math.cos(angle) * 2;
+        const startY = Math.sin(angle) * 2;
+        const endX = Math.cos(angle) * length;
+        const endY = Math.sin(angle) * length;
+        ctx.moveTo(startX, startY);
+        ctx.lineTo(endX, endY);
+      }
+      ctx.stroke();
+      break;
+
+    case "scribe":
+      // Musical note icons floating up
+      ctx.fillStyle = "#4444cc";
+      ctx.font = "bold 10px monospace";
+      ctx.textBaseline = "middle";
+      ctx.textAlign = "center";
+      // Animate vertical offset and opacity
+      const offsetY = -frame * 3;
+      const alpha = 1 - frame * 0.25;
+      ctx.globalAlpha = alpha;
+      ctx.fillText("♪", 0, offsetY);
+      ctx.globalAlpha = 1;
+      break;
+
+    case "healing":
+      // Concentric magic circles expanding
+      ctx.strokeStyle = "#44cc88";
+      ctx.lineWidth = 1.5;
+      const maxRadius = 6;
+      for (let i = 0; i < 3; i++) {
+        const radius = ((frame + i) % 4) * (maxRadius / 4) + 2;
+        ctx.beginPath();
+        ctx.arc(0, 0, radius, 0, Math.PI * 2);
+        ctx.stroke();
+      }
+      break;
+
+    case "watchtower":
+      // Exclamation alert icons
+      ctx.fillStyle = "#cc4444";
+      ctx.font = "bold 12px monospace";
+      ctx.textBaseline = "middle";
+      ctx.textAlign = "center";
+      // Blink effect on frames 0 and 2
+      if (frame % 2 === 0) {
+        ctx.fillText("!", 0, 0);
+      }
+      break;
+
+    default:
+      break;
+  }
+  ctx.restore();
+}
+
+// --- Add calls to drawSoundIndicator near relevant furniture functions (~line 676)
+
+// Assuming furniture drawing functions are named drawWorkshopForge, drawScribeStudy, drawHealingChamber, drawWatchtower
+// We add calls to drawSoundIndicator with appropriate type and frame
+
+// We patch existing furniture drawing functions by wrapping or injecting calls
+
+// We need a helper to get current animation frame for sound indicators (0..3)
+function getSoundIndicatorFrame() {
+  const now = Date.now();
+  return Math.floor(now / 150) % 4;
+}
+
+// Patch or add near furniture drawing functions (assuming they exist)
+
+// Example patch for workshop forge furniture (line ~676)
+// We add a wrapper or patch function here for demonstration
+
+// Since full furniture code is not provided, we add example hooks below:
+
+// Exported function to draw furniture with sound indicator
+// This is a minimal example to show usage; actual furniture draw functions may differ
+
+// We assume furniture drawing functions receive ctx, x, y
+
+// We add a new exported function to draw sound indicators near furniture
+
+export function drawFurnitureSoundIndicator(ctx: CanvasRenderingContext2D, furnitureType: string, x: number, y: number) {
+  const frame = getSoundIndicatorFrame();
+  switch (furnitureType) {
+    case "workshopForge":
+      drawSoundIndicator(ctx, x + 10, y + 4, "forge", frame);
+      break;
+    case "scribeStudy":
+      drawSoundIndicator(ctx, x + 6, y + 0, "scribe", frame);
+      break;
+    case "healingChamber":
+      drawSoundIndicator(ctx, x + 8, y + 6, "healing", frame);
+      break;
+    case "watchtower":
+      drawSoundIndicator(ctx, x + 8, y + 2, "watchtower", frame);
+      break;
+    default:
+      break;
+  }
+}
